package com.cho2hand.marketplace.entity.chat; import jakarta.persistence.*; import java.time.Instant;
@Entity @Table(name="messages") public class Message { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="message_id") private Long id; @Column(name="conversation_id") private Long conversationId; @Column(name="sender_user_id") private Long senderUserId; @Column(nullable=false) private String body; @Column(name="sent_at") private Instant sentAt; private String status; @PrePersist void sent(){sentAt=Instant.now();status="SENT";} public Long getId(){return id;} public Long getConversationId(){return conversationId;} public void setConversationId(Long v){conversationId=v;} public Long getSenderUserId(){return senderUserId;} public void setSenderUserId(Long v){senderUserId=v;} public String getBody(){return body;} public void setBody(String v){body=v;} public Instant getSentAt(){return sentAt;} }
